+	if !strings.Contains(plain, "✓") {
+		t.Errorf("SuccessMessage() = %q, should contain ✓", plain)
+	}
+	if !strings.Contains(plain, "done") {
+		t.Errorf("SuccessMessage() = %q, should contain 'done'", plain)
+	}
+}
+
