+func TestTruncateSubject_MarkdownHeading(t *testing.T) {
+	t.Parallel()
+	tests := []struct {
+		input string
+		want  string
+	}{
+		{"# Title", "Title"},
+		{"## Subtitle", "Subtitle"},
+		{"### Section", "Section"},
+	}
+	for _, tt := range tests {
+		got := truncateSubject(tt.input, 50)
+		if got != tt.want {
+			t.Errorf("truncateSubject(%q) = %q, want %q", tt.input, got, tt.want)
+		}
+	}
+}
