+package config
+
+import (
+	"os"
+	"path/filepath"
+	"testing"
+)
+
+// =============================================================================
+// GetValue tests (26.7% → target >80%)
+// =============================================================================
+
+func TestGetValue_NilConfig(t *testing.T) {
+	t.Parallel()
+	_, err := GetValue(nil, "theme")
+	if err == nil {
+		t.Error("GetValue(nil, ...) should return error")
+	}
+}
+
+func TestGetValue_EmptyPath(t *testing.T) {
